create table performance_schema.accounts
(
    USER                char(32) collate utf8_bin null,
    HOST                char(60) collate utf8_bin null,
    CURRENT_CONNECTIONS bigint                    not null,
    TOTAL_CONNECTIONS   bigint                    not null
)
    engine = PERFORMANCE_SCHEMA;

create table mysql.columns_priv
(
    Host        char(60)                                                      default ''                not null,
    Db          char(64)                                                      default ''                not null,
    User        char(32)                                                      default ''                not null,
    Table_name  char(64)                                                      default ''                not null,
    Column_name char(64)                                                      default ''                not null,
    Timestamp   timestamp                                                     default CURRENT_TIMESTAMP not null on update CURRENT_TIMESTAMP,
    Column_priv set ('Select', 'Insert', 'Update', 'References') charset utf8 default ''                not null,
    primary key (Host, Db, User, Table_name, Column_name)
)
    comment 'Column privileges' engine = MyISAM
                                collate = utf8_bin;

create table __tencentdb__.`complete_cnt_sync-rwt9gdgv`
(
    path         varchar(256)  not null
        primary key,
    complete_cnt int default 0 not null
)
    collate = latin1_general_cs;

create table performance_schema.cond_instances
(
    NAME                  varchar(128)    not null,
    OBJECT_INSTANCE_BEGIN bigint unsigned not null
)
    engine = PERFORMANCE_SCHEMA;

create table __tencentdb__.`cos_offset_sync-rwt9gdgv`
(
    table_name varchar(256) not null
        primary key,
    offset     varchar(256) null
)
    collate = latin1_general_cs;

create table mysql.db
(
    Host                  char(60)                     default ''  not null,
    Db                    char(64)                     default ''  not null,
    User                  char(32)                     default ''  not null,
    Select_priv           enum ('N', 'Y') charset utf8 default 'N' not null,
    Insert_priv           enum ('N', 'Y') charset utf8 default 'N' not null,
    Update_priv           enum ('N', 'Y') charset utf8 default 'N' not null,
    Delete_priv           enum ('N', 'Y') charset utf8 default 'N' not null,
    Create_priv           enum ('N', 'Y') charset utf8 default 'N' not null,
    Drop_priv             enum ('N', 'Y') charset utf8 default 'N' not null,
    Grant_priv            enum ('N', 'Y') charset utf8 default 'N' not null,
    References_priv       enum ('N', 'Y') charset utf8 default 'N' not null,
    Index_priv            enum ('N', 'Y') charset utf8 default 'N' not null,
    Alter_priv            enum ('N', 'Y') charset utf8 default 'N' not null,
    Create_tmp_table_priv enum ('N', 'Y') charset utf8 default 'N' not null,
    Lock_tables_priv      enum ('N', 'Y') charset utf8 default 'N' not null,
    Create_view_priv      enum ('N', 'Y') charset utf8 default 'N' not null,
    Show_view_priv        enum ('N', 'Y') charset utf8 default 'N' not null,
    Create_routine_priv   enum ('N', 'Y') charset utf8 default 'N' not null,
    Alter_routine_priv    enum ('N', 'Y') charset utf8 default 'N' not null,
    Execute_priv          enum ('N', 'Y') charset utf8 default 'N' not null,
    Event_priv            enum ('N', 'Y') charset utf8 default 'N' not null,
    Trigger_priv          enum ('N', 'Y') charset utf8 default 'N' not null,
    primary key (Host, Db, User)
)
    comment 'Database privileges' engine = MyISAM
                                  collate = utf8_bin;

create index User
    on mysql.db (User);

create table __tencentdb__.`eg_sync-rwt9gdgv`
(
    id            bigint auto_increment
        primary key,
    executed_gtid text not null comment 'number of interval.'
);

create table mysql.engine_cost
(
    engine_name varchar(64)                         not null,
    device_type int                                 not null,
    cost_name   varchar(64)                         not null,
    cost_value  float                               null,
    last_update timestamp default CURRENT_TIMESTAMP not null on update CURRENT_TIMESTAMP,
    comment     varchar(1024)                       null,
    primary key (cost_name, engine_name, device_type)
)
    charset = utf8;

create table mysql.event
(
    db                   char(64) collate utf8_bin                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           default ''                    not null,
    name                 char(64)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            default ''                    not null,
    body                 longblob                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          not null,
    definer              char(93) collate utf8_bin                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           default ''                    not null,
    execute_at           datetime                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          null,
    interval_value       int                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               null,
    interval_field       enum ('YEAR', 'QUARTER', 'MONTH', 'DAY', 'HOUR', 'MINUTE', 'WEEK', 'SECOND', 'MICROSECOND', 'YEAR_MONTH', 'DAY_HOUR', 'DAY_MINUTE', 'DAY_SECOND', 'HOUR_MINUTE', 'HOUR_SECOND', 'MINUTE_SECOND', 'DAY_MICROSECOND', 'HOUR_MICROSECOND', 'MINUTE_MICROSECOND', 'SECOND_MICROSECOND')                                                                                                                                                                                                                                                                                                                                               null,
    created              timestamp                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           default CURRENT_TIMESTAMP     not null on update CURRENT_TIMESTAMP,
    modified             timestamp                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           default '0000-00-00 00:00:00' not null,
    last_executed        datetime                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          null,
    starts               datetime                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          null,
    ends                 datetime                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          null,
    status               enum ('ENABLED', 'DISABLED', 'SLAVESIDE_DISABLED')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  default 'ENABLED'             not null,
    on_completion        enum ('DROP', 'PRESERVE')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           default 'DROP'                not null,
    sql_mode             set ('REAL_AS_FLOAT', 'PIPES_AS_CONCAT', 'ANSI_QUOTES', 'IGNORE_SPACE', 'NOT_USED', 'ONLY_FULL_GROUP_BY', 'NO_UNSIGNED_SUBTRACTION', 'NO_DIR_IN_CREATE', 'POSTGRESQL', 'ORACLE', 'MSSQL', 'DB2', 'MAXDB', 'NO_KEY_OPTIONS', 'NO_TABLE_OPTIONS', 'NO_FIELD_OPTIONS', 'MYSQL323', 'MYSQL40', 'ANSI', 'NO_AUTO_VALUE_ON_ZERO', 'NO_BACKSLASH_ESCAPES', 'STRICT_TRANS_TABLES', 'STRICT_ALL_TABLES', 'NO_ZERO_IN_DATE', 'NO_ZERO_DATE', 'INVALID_DATES', 'ERROR_FOR_DIVISION_BY_ZERO', 'TRADITIONAL', 'NO_AUTO_CREATE_USER', 'HIGH_NOT_PRECEDENCE', 'NO_ENGINE_SUBSTITUTION', 'PAD_CHAR_TO_FULL_LENGTH') default ''                    not null,
    comment              char(64) collate utf8_bin                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           default ''                    not null,
    originator           int unsigned                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      not null,
    time_zone            char(64) charset latin1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             default 'SYSTEM'              not null,
    character_set_client char(32) collate utf8_bin                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         null,
    collation_connection char(32) collate utf8_bin                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         null,
    db_collation         char(32) collate utf8_bin                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         null,
    body_utf8            longblob                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          null,
    primary key (db, name)
)
    comment 'Events' engine = MyISAM
                     charset = utf8;

