create table mysql.slave_master_info
(
    Number_of_lines        int unsigned              not null comment 'Number of lines in the file.',
    Master_log_name        text collate utf8_bin     not null comment 'The name of the master binary log currently being read from the master.',
    Master_log_pos         bigint unsigned           not null comment 'The master log position of the last read event.',
    Host                   char(64) collate utf8_bin null comment 'The host name of the master.',
    User_name              text collate utf8_bin     null comment 'The user name used to connect to the master.',
    User_password          text collate utf8_bin     null comment 'The password used to connect to the master.',
    Port                   int unsigned              not null comment 'The network port used to connect to the master.',
    Connect_retry          int unsigned              not null comment 'The period (in seconds) that the slave will wait before trying to reconnect to the master.',
    Enabled_ssl            tinyint(1)                not null comment 'Indicates whether the server supports SSL connections.',
    Ssl_ca                 text collate utf8_bin     null comment 'The file used for the Certificate Authority (CA) certificate.',
    Ssl_capath             text collate utf8_bin     null comment 'The path to the Certificate Authority (CA) certificates.',
    Ssl_cert               text collate utf8_bin     null comment 'The name of the SSL certificate file.',
    Ssl_cipher             text collate utf8_bin     null comment 'The name of the cipher in use for the SSL connection.',
    Ssl_key                text collate utf8_bin     null comment 'The name of the SSL key file.',
    Ssl_verify_server_cert tinyint(1)                not null comment 'Whether to verify the server certificate.',
    Heartbeat              float                     not null,
    Bind                   text collate utf8_bin     null comment 'Displays which interface is employed when connecting to the MySQL server',
    Ignored_server_ids     text collate utf8_bin     null comment 'The number of server IDs to be ignored, followed by the actual server IDs',
    Uuid                   text collate utf8_bin     null comment 'The master server uuid.',
    Retry_count            bigint unsigned           not null comment 'Number of reconnect attempts, to the master, before giving up.',
    Ssl_crl                text collate utf8_bin     null comment 'The file used for the Certificate Revocation List (CRL)',
    Ssl_crlpath            text collate utf8_bin     null comment 'The path used for Certificate Revocation List (CRL) files',
    Enabled_auto_position  tinyint(1)                not null comment 'Indicates whether GTIDs will be used to retrieve events from the master.',
    Channel_name           char(64)                  not null comment 'The channel on which the slave is connected to a source. Used in Multisource Replication'
        primary key,
    Tls_version            text collate utf8_bin     null comment 'Tls version'
)
    comment 'Master Information' charset = utf8;

create table mysql.slave_relay_log_info
(
    Number_of_lines   int unsigned          not null comment 'Number of lines in the file or rows in the table. Used to version table definitions.',
    Relay_log_name    text collate utf8_bin not null comment 'The name of the current relay log file.',
    Relay_log_pos     bigint unsigned       not null comment 'The relay log position of the last executed event.',
    Master_log_name   text collate utf8_bin not null comment 'The name of the master binary log file from which the events in the relay log file were read.',
    Master_log_pos    bigint unsigned       not null comment 'The master log position of the last executed event.',
    Sql_delay         int                   not null comment 'The number of seconds that the slave must lag behind the master.',
    Number_of_workers int unsigned          not null,
    Id                int unsigned          not null comment 'Internal Id that uniquely identifies this record.',
    Channel_name      char(64)              not null comment 'The channel on which the slave is connected to a source. Used in Multisource Replication'
        primary key
)
    comment 'Relay Log Information' charset = utf8;

create table mysql.slave_worker_info
(
    Id                         int unsigned          not null,
    Relay_log_name             text collate utf8_bin not null,
    Relay_log_pos              bigint unsigned       not null,
    Master_log_name            text collate utf8_bin not null,
    Master_log_pos             bigint unsigned       not null,
    Checkpoint_relay_log_name  text collate utf8_bin not null,
    Checkpoint_relay_log_pos   bigint unsigned       not null,
    Checkpoint_master_log_name text collate utf8_bin not null,
    Checkpoint_master_log_pos  bigint unsigned       not null,
    Checkpoint_seqno           int unsigned          not null,
    Checkpoint_group_size      int unsigned          not null,
    Checkpoint_group_bitmap    blob                  not null,
    Channel_name               char(64)              not null comment 'The channel on which the slave is connected to a source. Used in Multisource Replication',
    primary key (Channel_name, Id)
)
    comment 'Worker Information' charset = utf8;

create table mysql.slow_log
(
    start_time     timestamp(6) default CURRENT_TIMESTAMP(6) not null on update CURRENT_TIMESTAMP(6),
    user_host      mediumtext                                not null,
    query_time     time(6)                                   not null,
    lock_time      time(6)                                   not null,
    rows_sent      int                                       not null,
    rows_examined  int                                       not null,
    db             varchar(512)                              not null,
    last_insert_id int                                       not null,
    insert_id      int                                       not null,
    server_id      int unsigned                              not null,
    sql_text       mediumblob                                not null,
    thread_id      bigint(21) unsigned                       not null
)
    comment 'Slow log' engine = CSV
                       charset = utf8;

