    alive_id   varchar(64)                             not null comment '直播id',
    coupon_id  varchar(64)                             not null comment '优惠券id',
    state      tinyint   default 0                     null comment '状态 0-正常，1-隐藏，2-删除',
    created_at timestamp default CURRENT_TIMESTAMP     not null comment '创建时间',
    updated_at timestamp default '0000-00-00 00:00:00' not null on update CURRENT_TIMESTAMP comment '更新时间，有修改自动更新',
    primary key (app_id, alive_id, coupon_id)
)
    comment '直播优惠券关系记录表';

create index index_coupon_id
    on db_ex_alive_coupon.t_alive_coupon (coupon_id);

create index index_created_at
    on db_ex_alive_coupon.t_alive_coupon (created_at);

create table db_ex_alive_goods.t_alive_goods
(
    id                 bigint unsigned auto_increment comment '主键ID'
        primary key,
