    goods_desc         varchar(64) default ''                not null comment '亮点描述',
    row_state          tinyint     default 0                 not null comment '行状态 0-正常 1-删除',
    created_at         datetime    default CURRENT_TIMESTAMP not null comment '创建时间',
    updated_at         datetime    default CURRENT_TIMESTAMP not null on update CURRENT_TIMESTAMP comment '更新时间',
    is_preheat         tinyint     default 0                 not null comment '是否隐藏价格：默认0不隐藏(开价)，1隐藏(预热)',
    constraint idx_app_alive_resource
        unique (app_id, alive_id, resource_id)
