create table db_ex_alive_market.t_alive_goods_status
(
    id          bigint unsigned auto_increment comment '主键id'
        primary key,
    alive_id    varchar(64) default ''                    not null comment '直播间id',
    app_id      varchar(64) default ''                    not null comment '店铺id',
    resource_id varchar(64) default ''                    not null comment '资源id',
    is_sell_out tinyint     default 0                     not null comment '该商品是否售罄 1-已售罄 0-未售罄',
    created_at  timestamp   default CURRENT_TIMESTAMP     not null comment '创建时间',
    updated_at  timestamp   default '0000-00-00 00:00:00' not null on update CURRENT_TIMESTAMP comment '更新时间，有修改自动更新',
    constraint unx_app_alive_resource
        unique (app_id, alive_id, resource_id)
)
    comment '直播带货商品状态表';

create table db_ex_alive_conf.t_alive_market_conf
(
    app_id                      varchar(64)                                 not null comment '应用id',
    alive_id                    varchar(64)                                 not null comment '直播id',
    is_show_stock               tinyint       default 0                     null comment '是否开启库存显示，0-关闭 1-开启',
    is_show_gift_on             tinyint       default 0                     null comment '是否开启礼物显示，0-关闭 1-开启',
    everybody_talk_on           tinyint       default 0                     not null comment '讲师设置大家说开关，0-关闭 1-开启',
    auto_talk_on                tinyint       default 0                     not null comment '自动触发大家说开关，0-关闭 1-开启',
    auto_talk_repeat_num        int           default 0                     not null comment '自动触发大家说重复次数',
    again_comment_on            tinyint       default 1                     not null comment '评论+1开关，0-关闭 1-开启',
    order_comment_on            tinyint       default 0                     not null comment '下单评论开关，0-关闭 1-开启',
    created_at                  timestamp     default CURRENT_TIMESTAMP     not null comment '创建时间',
    updated_at                  timestamp     default '0000-00-00 00:00:00' not null on update CURRENT_TIMESTAMP comment '更新时间，有修改自动更新',
    is_hot_sales_on             tinyint       default 0                     not null comment '是否开启热卖显示，0-关闭 1-开启',
    hot_conf                    varchar(2048) default ''                    not null comment '热卖配置内容',
    is_red_packet_on            tinyint       default 0                     null comment '是否开启红包，0-关闭 1-开启',
    is_point_red_packet_on      tinyint       default 0                     null comment '是否开启积分红包，0-关闭 1-开启',
    is_password_red_packet_on   varchar(512)  default ''                    null comment '口令红包开关，json字符串',
    is_takegoods                tinyint       default 0                     not null comment '是否开启直播带货，0-关闭 1-开启',
    takegoods                   int           default 0                     not null comment '直播带货，商品所存的商品分组ID，0代表没有',
    is_coupon_on                tinyint       default 0                     not null comment '是否开启关联优惠券，0-关闭 1-开启',
    is_card_on                  tinyint       default 0                     not null comment '是否开启关联卡片，0-关闭 1-开启',
    coupon_conf                 varchar(2048) default ''                    not null comment '优惠券配置',
    goods_conf                  varchar(2048) default ''                    not null comment '带货配置内容',
    is_time_limit_red_packet_on varchar(512)  default ''                    null comment '限时红包开关 JSON字符串',
    is_goods_tag_group_on       tinyint       default 0                     not null comment '是否在直播间开启带货标签组功能，0-关，1-开',
    primary key (app_id, alive_id)
)
    comment '直播营销配置表';

create index index_alive_id
    on db_ex_alive_conf.t_alive_market_conf (alive_id);

create index index_created_at
    on db_ex_alive_conf.t_alive_market_conf (created_at);

