    is_red_packet_on            tinyint       default 0                     null comment '是否开启红包，0-关闭 1-开启',
    is_point_red_packet_on      tinyint       default 0                     null comment '是否开启积分红包，0-关闭 1-开启',
    is_password_red_packet_on   varchar(512)  default ''                    null comment '口令红包开关，json字符串',
    coupon_conf                 varchar(2048) default ''                    not null comment '优惠券配置',
    goods_conf                  varchar(2048) default ''                    not null comment '带货配置内容',
    prize_limit_conf            varchar(2048) default ''                    not null comment '限制中奖配置内容',
    red_packet_receive_limit    int           default 0                     not null comment '红包领取限制',
    is_time_limit_red_packet_on varchar(512)  default ''                    null comment '限时红包开关 JSON字符串',
    task_conf                   varchar(2048) default ''                    not null comment '任务配置内容'
)
    comment '直播营销店铺配置表';

