create table db_red_packet.t_red_packet
(
    id                          bigint auto_increment
        primary key,
    app_id                      varchar(64)                                not null comment '店铺Id',
    order_id                    varchar(64)                                not null comment '关联订单Id',
    user_id                     varchar(64)                                not null comment '红包发起人',
    resource_id                 varchar(64)                                not null comment '资源Id',
    resource_type               int                                        not null comment '资源类型',
    r_type                      tinyint(1)   default 1                     not null comment '红包类型;1-普通红包',
    biz_type                    tinyint      default 1                     not null comment '业务来源类型 1直播间红包 2直播间任务 其他待定',
    state                       tinyint(1)   default 1                     not null comment '红包状态;0-预创建,1-进行中,2-已结束,3-已过期,4-异常红包',
    receive_type                tinyint(1)                                 not null comment '领取类型;1-拼手气红包,2-等额红包',
    money                       int                                        not null comment '原始金额(分)',
    after_deduction_money       int                                        not null comment '扣除手续费后金额(分)',
    num                         int                                        not null comment '红包个数',
    describe_msg                varchar(255) default ''                    null comment '红包描述',
    is_deleted                  tinyint(1)   default 0                     not null comment '0-正常,1-已删除',
    created_at                  timestamp    default CURRENT_TIMESTAMP     not null comment '创建时间',
    updated_at                  timestamp    default '0000-00-00 00:00:00' not null on update CURRENT_TIMESTAMP comment '更新时间',
    refund_money                int          default 0                     null comment '退款金额',
    refund_time                 timestamp    default '0000-00-00 00:00:00' null comment '退款时间',
    average_price               int          default 0                     null comment 'receive=2时 记录单个金额',
    remark                      varchar(255) default ''                    not null comment '备注',
    ext_info                    varchar(512)                               null comment '扩展字段',
    red_packet_password         varchar(512) default ''                    null comment '红包口令',
    roi_rule_type               tinyint      default 0                     not null comment 'roi规则类型：0无限制 1指定等级会员 2指定标签参与 3指定标签不可参与',
    red_packet_time_limit       tinyint      default 0                     null comment '限时红包开关 0-关闭 1-开启',
    cancel_user_id              varchar(64)  default ''                    null comment '限时红包手动结束人',
    red_packet_limited_duration int          default 0                     null comment '限时时长,秒级时间戳',
    constraint unique_index_order
        unique (order_id)
)
    comment '红包表';

