create table db_red_packet.t_red_packet_count
(
    id               bigint auto_increment comment '主键id'
        primary key,
    pay_amount_total bigint    default 0                     not null comment '充值红包金额,单位:分',
    money_total      bigint    default 0                     not null comment '发送红包金额,单位:分',
    red_count        bigint    default 0                     not null comment '发送红包个数',
    shop_count       bigint    default 0                     not null comment '发送红包店铺数',
    resource_count   bigint    default 0                     not null comment '发送红包直播数',
    teacher_count    bigint    default 0                     not null comment '发送红包讲师数',
    receive_user_ids bigint    default 0                     not null comment '领取红包人数',
    created_at       timestamp default CURRENT_TIMESTAMP     not null comment '创建时间',
    updated_at       timestamp default '0000-00-00 00:00:00' not null on update CURRENT_TIMESTAMP comment '更新时间',
    r_type           tinyint   default 1                     not null comment '红包类型;1-普通红包 3-积分红包'
)
    comment '红包业务统计表';

