create table db_ex_alive_market.t_task
(
    id                bigint auto_increment comment '主键ID'
        primary key,
    app_id            varchar(64)   default ''                    not null comment '店铺ID',
    task_module       tinyint       default 0                     not null comment '任务模块 0-单项任务，1-组合任务',
    task_is_major     tinyint       default 0                     not null comment '是否主任务，0-是，1-否',
    task_title        varchar(255)  default ''                    not null comment '任务标题',
    task_is_order     tinyint       default 0                     not null comment '是否按顺序完成,0否，1是',
    task_type         tinyint       default 0                     not null comment '任务类型：1=观看任务，2=互动任务，3=消费任务，4=活跃任务',
    task_condition    varchar(1000) default ''                    not null comment '任务条件：观看任务时填写具体分钟值，互动任务时：1-评论 2-分享（21分享拉人，22分享拉新） 3-点赞，消费任务时：4-下单笔数 5-消费金额，活跃任务时：6-打赏 7-投票 8-问卷 9-签到 10-答题',
    level_member_rank varchar(1024) default ''                    not null comment '等级会员ID',
    state             tinyint       default 1                     not null comment '任务状态:0-已删除,1-正常，2-已停止',
    reward_type       tinyint       default 0                     not null comment '奖励类型：1=积分，2=优惠券，3=红包，4=课程/商品，5=自定义奖品',
    reward_pay_type   tinyint       default 0                     not null comment '奖励支付类型 0->总部支付（原逻辑）、10->门店支付',
    reward_frequency  varchar(32)   default ''                    not null comment '满足奖励所需频次，消费：满足多少笔、多少金额；答题：答对几道；分享：拉人/拉新人数；',
    reward_value      varchar(1000) default ''                    not null comment '奖励值：积分数值、优惠券码、红包、商品、自定义奖品等。如果奖品存在多个字段，存储成json格式）',
    is_show_answer    tinyint       default 0                     not null comment 'c端是否展示答案解析，0不展示',
    answer_chance     int           default 1                     not null comment '答题机会',
    start_at          timestamp     default '0000-00-00 00:00:00' not null comment '任务开始时间',
    end_at            timestamp     default '0000-00-00 00:00:00' not null comment '任务结束时间',
    created_at        timestamp     default CURRENT_TIMESTAMP     not null comment '创建时间',
    updated_at        timestamp     default '0000-00-00 00:00:00' not null on update CURRENT_TIMESTAMP comment '更新时间',
    roi_rule_type     tinyint       default 0                     not null comment 'roi规则类型：0无限制 1指定等级会员 2指定标签参与 3指定标签不可参与'
)
    comment '任务配置表';

